def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        score = 0.0
        complex_factor = 1.0
        decay = 1.0
        extra = 0.0
        multiplier = 1.0
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 5:
            for k in range(1, 10):
                score += ((-1) ** k) * np.log1p(ratio ** k) / (k**2 + 1)
            for j in range(1, 7):
                decay *= np.exp(-j / (ratio + j))
            multiplier = 5
            if item > capacity * 6:
                multiplier *= 2
            score = abs(score) * decay * multiplier
            priorities[i] = score
        elif 3 < ratio <= 5:
            temp_sum = 0
            for a in range(1, 20):
                if a % 2 == 0:
                    temp_sum += np.sin(ratio * a) / (a + ratio)
                else:
                    temp_sum -= np.cos(ratio / (a + 1)) / (a + 2)
            for b in range(1, 5):
                complex_factor *= (1 + b/(ratio + 2)) ** 0.5
            score = abs(temp_sum) * complex_factor * 10
            priorities[i] = score
        elif 1.5 < ratio <= 3:
            temp = 0
            for c in range(1, 15):
                if c % 3 == 0:
                    temp += (ratio ** c) / (c ** 1.5 + 1)
                else:
                    temp -= (ratio ** (c / 2)) / (c + 2)
            for d in range(2, 8):
                decay *= (1 - np.tanh(ratio / d) / (d + 1))
            multiplier = 20 if ratio < 2.5 else 15
            if ratio > 2.8:
                for e in range(1, 5):
                    extra += np.sqrt(ratio + e) / (e * 2)
                multiplier += extra
            score = abs(temp) * decay * multiplier
            priorities[i] = score
        elif 0 < ratio <= 1.5:
            temp_score = 0
            for f in range(1, 25):
                if f % 5 == 0:
                    temp_score += np.log1p(ratio ** f) / (f + 1)
                elif f % 4 == 0:
                    temp_score -= np.exp(-ratio * f / (f + 2))
                else:
                    temp_score += np.sin(ratio * f) / (f * 3)
            if ratio < 0.1:
                multiplier = 40
            elif ratio < 0.5:
                multiplier = 25
            elif ratio < 1:
                multiplier = 12
            else:
                multiplier = 8
            for g in range(1, 4):
                decay *= (1 - 1 / ((g + 1) * (ratio + 1)))
            score = abs(temp_score) * multiplier * decay
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
    for i in range(len(priorities)):
        if priorities[i] != np.inf and bins[i] > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + z ** 2 / (bins[i] + z))
            priorities[i] *= factor
        elif bins[i] <= 0:
            priorities[i] = np.inf
    return priorities
